import { useState, useRef, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const containerRef = useRef(null)

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [logoSize, setLogoSize] = useState(220)

  const [logoRotation, setLogoRotation] = useState(0)

  const [logoWarp, setLogoWarp] = useState(0)

  const [fabricDepth, setFabricDepth] = useState(8)

  const [glossIntensity, setGlossIntensity] = useState(40)

  const [isDragging, setIsDragging] = useState(false)

  const [activePreset, setActivePreset] = useState('front')

  const [logoPosition, setLogoPosition] = useState({
    x: 50,
    y: 42
  })

  useEffect(() => {

    const handleKeyDown = (e) => {

      const step = 1

      if (e.key === 'ArrowUp') {
        setLogoPosition(prev => ({
          ...prev,
          y: prev.y - step
        }))
      }

      if (e.key === 'ArrowDown') {
        setLogoPosition(prev => ({
          ...prev,
          y: prev.y + step
        }))
      }

      if (e.key === 'ArrowLeft') {
        setLogoPosition(prev => ({
          ...prev,
          x: prev.x - step
        }))
      }

      if (e.key === 'ArrowRight') {
        setLogoPosition(prev => ({
          ...prev,
          x: prev.x + step
        }))
      }

      if (e.key === '[') {
        setLogoSize(prev =>
          Math.max(prev - 10, 60)
        )
      }

      if (e.key === ']') {
        setLogoSize(prev =>
          Math.min(prev + 10, 700)
        )
      }
    }

    window.addEventListener(
      'keydown',
      handleKeyDown
    )

    return () => {

      window.removeEventListener(
        'keydown',
        handleKeyDown
      )
    }

  }, [])

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {

      setUploadedLogo(
        URL.createObjectURL(file)
      )
    }
  }

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  const handleMouseMove = (e) => {

    if (!isDragging) return

    const rect =
      containerRef.current.getBoundingClientRect()

    const x =
      ((e.clientX - rect.left) / rect.width) * 100

    const y =
      ((e.clientY - rect.top) / rect.height) * 100

    setLogoPosition({
      x,
      y
    })
  }

  const handleMouseUp = () => {
    setIsDragging(false)
  }

  const setPreset = (type) => {

    setActivePreset(type)

    if (type === 'front') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(220)
    }

    if (type === 'left-chest') {
      setLogoPosition({ x: 38, y: 30 })
      setLogoSize(120)
    }

    if (type === 'oversized') {
      setLogoPosition({ x: 50, y: 48 })
      setLogoSize(420)
    }

    if (type === 'back') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(320)
    }

    if (type === 'sleeve') {
      setLogoPosition({ x: 72, y: 33 })
      setLogoSize(90)
    }
  }

  return (

    <div
      className="h-screen bg-black text-white overflow-hidden"
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">


        <div
          ref={containerRef}
          className="bg-[#0a0a0a] flex items-center justify-center relative overflow-hidden"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[950px] scale-110"
          />

          {uploadedLogo && (

            <>
              <img
                src={uploadedLogo}
                alt="logo"
                onMouseDown={() => setIsDragging(true)}
                className="absolute z-20 select-none"
                style={{
                  width: `${logoSize}px`,
                  top: `${logoPosition.y}%`,
                  left: `${logoPosition.x}%`,
                  transform: `
                    translate(-50%, -50%)
                    rotate(${logoRotation}deg)
                    perspective(900px)
                    rotateX(${logoWarp}deg)
                  `,
                  cursor: isDragging ? 'grabbing' : 'grab',
                  filter: `
                    contrast(1.03)
                    saturate(1.08)
                    brightness(1.02)
                    drop-shadow(0 ${fabricDepth}px ${fabricDepth * 2}px rgba(0,0,0,0.25))
                  `
                }}
                draggable={false}
              />

              <div
                className="absolute z-30 pointer-events-none"
                style={{
                  width: `${logoSize}px`,
                  height: `${logoSize}px`,
                  top: `${logoPosition.y}%`,
                  left: `${logoPosition.x}%`,
                  transform: `
                    translate(-50%, -50%)
                    rotate(${logoRotation}deg)
                  `,
                  background: `
                    linear-gradient(
                      135deg,
                      rgba(255,255,255,${glossIntensity / 500}),
                      rgba(255,255,255,0),
                      rgba(255,255,255,${glossIntensity / 700})
                    )
                  `,
                  mixBlendMode: 'screen'
                }}
              />

            </>

          )}

        </div>


        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">


          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>


          <div className="p-6 space-y-6">


            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {[
                  'front',
                  'left-chest',
                  'oversized',
                  'back',
                  'sleeve'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() => setPreset(item)}
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>


            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={handleUpload}
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>


            {uploadedLogo && (

              <button
                onClick={removeLogo}
                className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
              >

                REMOVE LOGO

              </button>

            )}


            <div>

              <div className="flex justify-between mb-3">

                <p className="text-xs text-white/60">
                  Gloss Effect
                </p>

                <p className="text-xs text-yellow-500 font-black">
                  {glossIntensity}
                </p>

              </div>

              <input
                type="range"
                min="0"
                max="100"
                value={glossIntensity}
                onChange={(e) =>
                  setGlossIntensity(e.target.value)
                }
                className="w-full"
              />

            </div>


            <div>

              <div className="flex justify-between mb-3">

                <p className="text-xs text-white/60">
                  Fabric Depth
                </p>

                <p className="text-xs text-yellow-500 font-black">
                  {fabricDepth}
                </p>

              </div>

              <input
                type="range"
                min="0"
                max="25"
                value={fabricDepth}
                onChange={(e) =>
                  setFabricDepth(e.target.value)
                }
                className="w-full"
              />

            </div>

          </div>

        </div>

      </div>

    </div>

  )
}
